def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        if ratio == 0:
            score = 0.0
        elif ratio == 1:
            score = 10 + capacity * 0.1
        elif ratio < 0.5:
            score = (1 / (ratio + 0.1)) + capacity * 0.05
            for k in range(1, 4):
                if k % 2 == 0:
                    score += (ratio ** k) / (capacity + k)
                else:
                    score -= (ratio ** k) * k / (capacity + 1)
        elif 0.5 <= ratio < 1:
            base = (ratio ** 2) * 5
            penalty = 0
            for idx in range(1, 6):
                penalty += ((-1) ** idx) * (ratio ** idx) / (idx + 0.3)
                if idx % 2 == 0 and ratio > 0.7:
                    penalty *= 1.1
            score = base + penalty + np.log(capacity + 1)
        elif 1 < ratio <= 2:
            score = (ratio ** 3) * 3
            factor = 1.0
            for x in range(1, 8):
                if x % 3 == 0:
                    factor += (ratio ** x) / (x + 0.7)
                else:
                    factor -= (ratio ** x) / (x + 1.3)
            score *= factor
            if capacity > item * 3:
                score /= (capacity / (item + 1))
        else:
            penalty = 0
            for p in range(1, 6):
                penalty += (ratio ** (2*p)) / (p * 2 + 1)
                if p % 2 == 0:
                    penalty -= (ratio ** p) / (p + 0.5)
            score = (ratio ** 4) - penalty + np.sqrt(capacity + 1)
            if ratio > 3:
                score += np.exp(ratio / (capacity + 1))
        if capacity == item:
            score += 7
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
